public async broadcastTransaction(
  signedTx: string,
): Promise<ethers.TransactionResponse> {
  const hashPromise = this.#hardhatProvider.request({
    method: "eth_sendRawTransaction",
    params: [signedTx],
  });

  const [hash, blockNumber] = await Promise.all([
    hashPromise,
    this.getBlockNumber(),
  ]);

  assertHardhatInvariant(typeof hash === "string", "hash should be a string");

  const tx = Transaction.from(signedTx);

  assertHardhatInvariant(
    tx.hash !== null,
    "Hash of signed tx shouldn't be null",
  );

  if (tx.hash !== hash) {
    throw new HardhatError(
      HardhatError.ERRORS.HARDHAT_ETHERS.GENERAL.BROADCASTED_TX_DIFFERENT_HASH,
      {
        txHash: tx.hash,
        broadcastedTxHash: hash,
      },
    );
  }

  // eslint-disable-next-line @typescript-eslint/consistent-type-assertions -- 'tx' overlaps with the type exported by ethers
  return this.#wrapTransactionResponse(tx as any).replaceableTransaction(
    blockNumber,
  );
}

async function sendDeclareV2Tx(
    signatures: string[],
    compiledClassHash: string,
    maxFee: Numeric,
    senderAddress: string,
    version: Numeric,
    nonce: Numeric,
    contractClass: Cairo1ContractClass
) {
    const hre = await import("hardhat");
    const resp = await axios
        .post(`${hre.starknet.networkConfig.url}/gateway/add_transaction`, {
            type: "DECLARE",
            contract_class: contractClass.getCompiledClass(),
            signature: signatures,
            sender_address: senderAddress,
            compiled_class_hash: compiledClassHash,
            version: numericToHexString(version),
            nonce: numericToHexString(nonce),
            max_fee: numericToHexString(maxFee)
        })
        .catch((error: AxiosError<starknet.StarkError>) => {
            const msg = `Declaring contract failed: ${error.response.data.message}`;
            throw new StarknetPluginError(msg, error);
        });

    return new Promise<string>((resolve, reject) => {
        iterativelyCheckStatus(
            resp.data.transaction_hash,
            hre.starknetWrapper,
            () => resolve(resp.data.transaction_hash),
            reject
        );
    });
}

public override async estimateDeployAccountFee(): Promise<starknet.FeeEstimation> {
    this.assertNotDeployed();
    const hre = await import("hardhat");

    const contractFactory = await OpenZeppelinAccount.getContractFactory();
    const classHash = await contractFactory.getClassHash();
    const constructorCalldata = [BigInt(this.publicKey).toString()];

    const maxFee = numericToHexString(0);
    const nonce = numericToHexString(0);

    const calldataHash = hash.computeHashOnElements([
        classHash,
        this.salt,
        ...constructorCalldata
    ]);
    const msgHash = hash.computeHashOnElements([
        TransactionHashPrefix.DEPLOY_ACCOUNT,
        numericToHexString(QUERY_VERSION),
        this.address,
        0, // entrypoint selector is implied
        calldataHash,
        maxFee,
        hre.starknet.networkConfig.starknetChainId,
        nonce
    ]);

    const signature = this.getSignatures(msgHash);
    const data = {
        type: "DEPLOY_ACCOUNT",
        class_hash: classHash,
        constructor_calldata: constructorCalldata,
        contract_address_salt: this.salt,
        signature: bnToDecimalStringArray(signature || []),
        version: numericToHexString(QUERY_VERSION),
        nonce
    };

    return await sendEstimateFeeTx(data);
}

function createIntegratedDevnet(hre: HardhatRuntimeEnvironment): ExternalServer {
    const devnetNetwork = getNetwork<HardhatNetworkConfig>(
        INTEGRATED_DEVNET,
        hre.config.networks,
        `networks["${INTEGRATED_DEVNET}"]`
    );
    const { hostname, port } = new URL(devnetNetwork.url || INTEGRATED_DEVNET_URL);

    if (hostname !== "localhost" && hostname !== "127.0.0.1") {
        throw new StarknetPluginError("Integrated devnet works only with localhost and 127.0.0.1");
    }

    if (devnetNetwork.venv) {
        return new VenvDevnet(
            devnetNetwork.venv,
            hostname,
            port,
            devnetNetwork?.args,
            devnetNetwork?.stdout,
            devnetNetwork?.stderr,
            devnetNetwork.vmLang
        );
    }

    if (hostname === "localhost") {
        throw new StarknetPluginError(
            "Dockerized integrated devnet works only with host 127.0.0.1"
        );
    }

    const image = getDevnetImage(devnetNetwork.dockerizedVersion);

    return new DockerDevnet(
        image,
        hostname,
        port,
        devnetNetwork?.args,
        devnetNetwork?.stdout,
        devnetNetwork?.stderr,
        devnetNetwork.vmLang
    );
}

export function inReceipt(receipt: ContractReceipt, eventName: string, eventArgs = {}): any {
  if (receipt.events == undefined) {
    throw new Error('No events found in receipt');
  }

  const events = receipt.events.filter((e) => e.event === eventName);
  expect(events.length > 0).to.equal(true, `No '${eventName}' events found`);

  const exceptions: Array<string> = [];
  const event = events.find(function (e) {
    for (const [k, v] of Object.entries(eventArgs)) {
      try {
        if (e.args == undefined) {
          throw new Error('Event has no arguments');
        }

        contains(e.args, k, v);
      } catch (error) {
        exceptions.push(error);
        return false;
      }
    }
    return true;
  });

  if (event === undefined) {
    // Each event entry may have failed to match for different reasons,
    // throw the first one
    throw exceptions[0];
  }

  return event;
}

